INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40000, 0, 91002, "", 36, 0, 0, "", 1, 8, 100);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 1, 91002, "今日は記念日、お祝いですね！\n焼肉、お寿司、ピザ、ケーキ～☆\nあなたとパーティできるなんて、\n幸せです～♪", 37, 107501, 0, "ぺコリーヌ", 1, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 1, 91002, "この記念日を迎えられたのは、\n主さまの器量の賜物\nさすがは主さまでございます\nえらい、えらい♪", 38, 107601, 0, "コッコロ", 2, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 1, 91002, "あんたもけっこうやるじゃない！\nちょっとは…割と…け、けっこう\n見直しちゃったわ\n褒めてあげる♪", 39, 107801, 0, "キャル", 3, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 1, 91002, "あなたと私にとって、\n今日は特別な日\nあなたの支えがあるから、\n私は頑張れるんです！", 40, 107701, 0, "スズメ", 4, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 1, 91002, "今日はキミにとっての\n特別な記念日だにゃ\nキミの活躍にはいつも\n猫ながら感謝してるにゃ～♪", 41, 107901, 0, "タマキ", 5, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 2, 91002, "う～かき氷食べ過ぎて、\n身体が冷えちゃいました…\nあなたの体温で温めてください！\nギューーッ♪", 42, 107501, 0, "ぺコリーヌ", 6, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 2, 91002, "夏は危険がいっぱいと申します…\nですが、わたくしが主さまを\nしっかりとお守りいたしますよ", 43, 107601, 0, "コッコロ", 7, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 2, 91002, "ん～なんであんたと、ひと夏を\n過ごすことになったのかな…\n結構楽しいからいいけど！\nさ、まだまだ遊ぶわよ！", 44, 107801, 0, "キャル", 8, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 2, 91002, "あなたと過ごすはじめての夏…\nいまからドキドキが止まりません\n楽しくて素敵な思い出が、\nまた一つ増えるんですね♪", 45, 107701, 0, "スズメ", 9, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40001, 2, 91002, "夏は一番の稼ぎ時にゃのに、\n今年はキミと過ごしたいって\n思ってるにゃ楽しい思い出\n増やしてくれるかにゃ？", 46, 107901, 0, "タマキ", 10, 8, 150);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40003, 0, 91002, "", 57, 0, 0, "", 1, 8, 150);
