INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 1, 24001, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 321, 125801, 0, "リリ", 1, 2, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 1, 24001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 322, 126001, 0, "クリア", 2, 2, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 1, 24001, "んーと。\nこれ、あげる。\nはい", 323, 126101, 0, "プレシア", 3, 2, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 2, 24001, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 324, 125801, 0, "リリ", 4, 2, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 2, 24001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 325, 126001, 0, "クリア", 5, 2, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 2, 24001, "お兄。\nきてくれて、うれしい", 326, 126101, 0, "プレシア", 6, 2, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (80009, 0, 91002, "", 327, 0, 532001, "", 1, 8, 100);
